ls -la /app/
rm -f /tmp/b64.*
cd /app && npm install 2>&1 | tail -5
pkill -f "node /app/server.js" 2>/dev/null; sleep 1
nohup env PORT=8080 DB_PATH=/app/data/artist_data.db node /app/server.js > /app/server.log 2>&1 &
sleep 3
ps aux | grep "node /app/server" | grep -v grep || (echo "SERVER_FAILED:" && cat /app/server.log)
curl -s http://localhost:8080/api/ping && echo "API_OK" || echo "API_FAIL"
